/**
 * The HarmonyProxyService request params.
 */
export interface HarmonyProxyRequestParams {
    /**
     * The HTTP request method (i.e GET, POST, PUT, DELETE). Defaults to GET.
     */
    method?: string;
    /**
     * One of the HarmonyProxyService endpoints defined [here](https://code.amazon.com/packages/HarmonyProxyInterface/blobs/mainline/--/README.md).
     */
    proxyOrigin?: string;
    /**
     * The HarmonyProxyService stage.
     */
    stage?: HarmonyStage | 'corp';
    /**
     * The HarmonyProxyService region.
     *
     * If the {@code proxyOrigin} is not specified, the combination of {@code stage} and {@code region} determines which
     * [HarmonyProxyService endpoint](https://code.amazon.com/packages/Harmony-navigation/blobs/mainline/--/src/config/proxy-config.js)
     * to use when executing the request.
     */
    region?: string;
    /**
     * The headers to include in the request.
     */
    headers?: StringMap;
    /**
     * The request payload.
     */
    data?: any;
    /**
     * The request timeout.
     */
    timeout?: number;
}
/**
 * The HarmonyProxyService /generic request params.
 */
export interface HarmonyGenericProxyRequestParams extends HarmonyProxyRequestParams {
    data: {
        url: string;
        method: string;
        headers?: StringMap;
        body?: any;
        connectTimeout?: number;
        socketTimeout?: number;
        responseHeaders?: string[];
    };
}
/**
 * Options that can be passed into the HarmonyProxyService /generic call
 */
export interface HarmonyGenericProxyRequestOptions {
    options: {
        retryAttempts: number;
    };
}
export interface HarmonyUser {
    login: string;
    email: string;
    firstName: string;
    lastName: string;
    costCenter: string;
    department: string;
    jobLevel: string;
    jobTitle: string;
    location: string;
    city: string;
    manager: string;
    startDate: string;
}
export interface HarmonyApp {
    bindleId: string;
    description: string;
    displayName: string;
    name: string;
    state: string;
    version: string;
}
export interface HarmonyApi {
    banners: HarmonyApiBanners;
    featureFlags: HarmonyApiFeatureFlags;
    bindle: HarmonyApiBindle;
    /**
     * Returns a Promise that resolves to the Harmony application details object.
     *
     * @param appName the app name to retrieve details for. Defaults to the current app.
     */
    getAppInfo: (appName?: string) => Promise<HarmonyApp>;
    /**
     * Returns the current Harmony application name.
     */
    getAppName: () => string;
    /**
     * Provide name of the current Space.
     */
    getSpaceId: () => string;
    /**
     * Returns the current App Session Id. Used mainly to tie metrics/logs together.
     */
    getAppSessionId: () => string;
    /**
     * Deprecates an app in the current stage. You must have permission to manage the app in order to deprecate it.
     */
    deprecateApp: (appName: string) => Promise<void>;
    /**
     * Returns the Harmony API base URL where the current user is authenticated.
     */
    getBaseUrl: () => string;
    /**
     * Returns the current Harmony stage.
     */
    getStage: () => HarmonyStage;
    /**
     * Returns details of the current login user.
     */
    getUser: () => HarmonyUser;
    /**
     * Returns the current login user name.
     */
    getUserName: () => string;
    /**
     * Executes a generic HarmonyProxyService request to the specified params.data.url.
     *
     * @return {Promise<XMLHttpRequest>} A promise that resolves to the [XMLHttpRequest](https://developer.mozilla.org/en-US/docs/Web/API/XMLHttpRequest) object
     *              once a server response is received by the service call. One must inspect the XMLHttpRequest object `status` (HTTP status code)
     *              to check whether the request is successful or not.
     */
    invokeGenericProxy: (params: HarmonyGenericProxyRequestParams, options?: HarmonyGenericProxyRequestOptions) => Promise<XMLHttpRequest>;
    /**
     * Executes HarmonyProxyService request to the specified path.
     *
     * @param {String} path the HarmonyProxyService path including any query parameters (will be prepended with /sentry-auth)
     * @param {HarmonyProxyRequestParams=} params an optional HarmonyProxyService request params.
     * @return {Promise<XMLHttpRequest>} A promise that resolves to the [XMLHttpRequest](https://developer.mozilla.org/en-US/docs/Web/API/XMLHttpRequest) object
     *              once a server response is received by the service call. One must inspect the XMLHttpRequest object `status` (HTTP status code)
     *              to check whether the request is successful or not.
     */
    invokeProxy: (path: string, params?: HarmonyProxyRequestParams) => Promise<XMLHttpRequest>;
    notifications: HarmonyApiNotifications;
    /**
     * Override the current Harmony stage and reload the page.
     */
    overrideStage: (stage?: string) => void;
    iamRoles: HarmonyApiIAMRoles;
    surveys: HarmonyApiSurveys;
    /**
     * AWS Region (e.g. us-west-2, us-east-1, eu-west-1) where the current login user is authenticated.
     */
    region: string;
}
